"""matplotlib.projections — projection registry."""

from matplotlib.projections.polar import PolarAxes

_projections = {
    'rectilinear': None,
    'polar': PolarAxes,
    'aitoff': None,
    'hammer': None,
    'mollweide': None,
    'lambert': None,
}


def get_projection_names():
    return list(_projections.keys())


def get_projection_class(projection=None):
    if projection is None or projection == 'rectilinear':
        from matplotlib.axes import Axes
        return Axes
    if projection == 'polar':
        return PolarAxes
    if projection == '3d':
        try:
            from mpl_toolkits.mplot3d import Axes3D
            return Axes3D
        except ImportError:
            pass
    from matplotlib.axes import Axes
    return Axes


def register_projection(cls):
    _projections[cls.name] = cls


def projection_factory(projection, figure, rect, **kwargs):
    cls = get_projection_class(projection)
    return cls(figure, rect, **kwargs) if cls else None
